// Configuración dinámica desde el webhook (formulario del cliente)
const input = $input.first().json;
const body = input.body || input;

// Marcas: OBLIGATORIO desde el webhook. Sin marcas, no corre.
const brands = body.brands;
if (!brands || brands.length === 0) {
  throw new Error('Se requieren marcas (brands) para ejecutar el workflow.');
}

// Sheet ID: OBLIGATORIO desde el webhook.
const sheetId = body.sheetId;
if (!sheetId) {
  // Si no hay sheetId (ej: Schedule Trigger), no hay nada que procesar
  return [];
}

// Datos del cliente
const clientEmail = body.clientEmail || '';
const myBrand = body.myBrand || brands[0];

// Seguidores opcionales desde webhook (si no vienen, se toman de Apify)
const followers = body.followers || {};

const plan = body.plan || 'basic';
const fromDate = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

return [{ brands, sheetId, clientEmail, myBrand, followers, plan, fromDate }];

try {
  const igData = $node["Run an Actor and get dataset"].json;
  const config = $('Set Config').first().json;
  const marcas = config.brands.map(b => b.toLowerCase());
  const seguidores = config.followers || {};

  // ── Parse Gemini response ──
  // N8N LangChain Gemini node returns content as a plain string in $json.content
  // (NOT nested as $json.content.parts[0].text which is the raw REST API format)
  let result;
  if ($json.pilar !== undefined || $json.sentimiento !== undefined) {
    // jsonOutput:true parsed JSON directly into $json
    result = $json;
  } else {
    const rawText = (
      (typeof $json.content === 'string' ? $json.content : '') ||
      ($json.content && $json.content.parts && $json.content.parts[0] && $json.content.parts[0].text) ||
      $json.text ||
      (typeof $json === 'string' ? $json : '')
    );
    if (!rawText) throw new Error('Gemini format unknown. Keys: ' + Object.keys($json || {}).join(',') + ' | ' + JSON.stringify($json).slice(0,150));
    const cleanText = rawText.replace(/```json/g,'').replace(/```/g,'').trim();
    result = JSON.parse(cleanText);
  }

  // ── Brand detection ──
  const caption = (igData.caption || '').toLowerCase();
  let owner = (igData.ownerUsername || '').toLowerCase().trim();
  let marcaFinal = '';
  let pilarFinal = result.pilar || 'Otros';

  if (marcas.includes(owner)) {
    marcaFinal = owner;
  } else {
    pilarFinal = 'Influencer';
    const hashtags = Array.isArray(igData.hashtags) ? igData.hashtags.join(' ').toLowerCase() : '';
    const usertags = Array.isArray(igData.taggedUsers)
      ? igData.taggedUsers.map(u => (u.username || u.name || '').toLowerCase()).join(' ')
      : '';
    const coauthors = Array.isArray(igData.coauthorProducers)
      ? igData.coauthorProducers.map(u => (u.username || '').toLowerCase()).join(' ')
      : '';
    const searchText = caption + ' ' + hashtags + ' ' + usertags + ' ' + coauthors;
    const encontrada = marcas.find(m => searchText.includes(m.replace(/[._]/g, '')));
    if (!encontrada) return null;
    marcaFinal = encontrada;
  }

  // ── Engagement ──
  const followersFromApify = igData.ownerFollowersCount || igData.followersCount || 0;
  const followersCount = followersFromApify >= 1000 ? followersFromApify : (seguidores[marcaFinal] || 100000);
  const eng = (((igData.likesCount || 0) + (igData.commentsCount || 0)) / followersCount * 100).toFixed(2) + '%';

  // ── Content type ──
  const ptRaw = (igData.productType || igData.type || '').toLowerCase();
  let contentType = 'IMAGE';
  if (ptRaw === 'clips' || ptRaw === 'graphvideo' || ptRaw === 'video') contentType = 'VIDEO';
  else if (ptRaw === 'sidecar' || ptRaw === 'graphsidecar') contentType = 'SIDECAR';
  else if (ptRaw === 'igtv') contentType = 'VIDEO';

  // ── Distribution ──
  const isSponsored = igData.isSponsored === true;
  const distribucion = isSponsored ? 'PAUTA' : (igData.likesCount > 400 ? 'PAUTA' : 'ORGÁNICO');

  // ── Date guard ──
  const _fecha = igData.timestamp ? new Date(igData.timestamp).toISOString().slice(0,10) : '2000-01-01';
  if (_fecha < config.fromDate) return null;

  return {
    marca: marcaFinal,
    pilar: pilarFinal,
    fecha: _fecha,
    distribucion,
    positivo: result.sentimiento?.positivo || 0,
    negativo: result.sentimiento?.negativo || 0,
    neutro: result.sentimiento?.neutro || 0,
    likes: igData.likesCount || 0,
    comments: igData.commentsCount || 0,
    engagement: eng,
    insight: result.insight || 'Sin análisis',
    url: igData.url,
    videoViews: igData.videoViewCount || igData.videoPlayCount || 0,
    contentType,
    isSponsored,
    hashtags: Array.isArray(igData.hashtags) ? igData.hashtags.join(',') : ''
  };

} catch (e) {
  return { marca: 'ERROR', insight: e.message };
}

const config = $('Set Config').first().json;
const clientEmail = config.clientEmail || '';
if (!clientEmail) return [];

const plan = config.plan || 'basic';
const dashboardUrl = 'https://smart-social-ai.vercel.app/Instagram_Intelligence%20(24).html?id=' 
  + config.sheetId + '&myBrand=' + encodeURIComponent(config.myBrand) + '&plan=' + plan;
const allPosts = $input.first().json.data || [];
const postCount = allPosts.length;

const isBasic = plan === 'basic';
const title = isBasic ? '\u00a1Tu Reporte Inicial ya est\u00e1 listo!' : '\u00a1Tu dashboard ya est\u00e1 listo!';
const subtitle = isBasic
  ? 'Tu marca + 2 competidores \u00b7 \u00daltimos 3 meses de posteos y comentarios'
  : 'El an\u00e1lisis de inteligencia competitiva de tus marcas en Instagram est\u00e1 disponible.';
const btnLabel = isBasic ? 'Ver mi Reporte' : 'Ver mi Dashboard';

const emailBody = '<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; background-color: #0f1117; color: #e2e8f0; padding: 40px; border-radius: 12px;">'
  + '<div style="margin-bottom: 32px;"><span style="font-size: 22px; font-weight: bold;"><span style="color: #38bdf8;">smart</span><span style="color: #ffffff;">Social</span> <span style="color: #38bdf8;">AI</span></span></div>'
  + '<h1 style="font-size: 28px; font-weight: bold; color: #ffffff; margin-bottom: 8px;">' + title + '</h1>'
  + '<p style="color: #94a3b8; font-size: 16px; margin-bottom: 32px;">' + subtitle + '</p>'
  + '<div style="background-color: #1e293b; border-radius: 10px; padding: 24px; margin-bottom: 32px;">'
  + '<p style="margin: 0 0 12px 0; font-size: 15px;"><strong>' + postCount + ' posts</strong> analizados con IA</p>'
  + (isBasic ? '<p style="margin: 0 0 12px 0; font-size: 15px;">Sentimiento \u00b7 benchmark \u00b7 recomendaciones</p>' : '')
  + '<p style="margin: 0; font-size: 15px; color: #64748b;">Entrega en 2 horas \u2713</p>'
  + '</div>'
  + '<a href="' + dashboardUrl + '" style="display: inline-block; background-color: #16a34a; color: #ffffff; text-decoration: none; padding: 14px 28px; border-radius: 8px; font-size: 16px; font-weight: bold; margin-bottom: 32px;">' + btnLabel + '</a>'
  + '<hr style="border: none; border-top: 1px solid #1e293b; margin: 32px 0;" />'
  + '<p style="color: #475569; font-size: 12px; margin: 0;">\u00bfAlg\u00fan problema? Escribinos a <a href="mailto:hola@smartsocial.ai" style="color: #38bdf8;">hola@smartsocial.ai</a></p>'
  + '</div>';

return [{ clientEmail, dashboardUrl, postCount, plan, emailBody }];

// Collect existing post URLs for deduplication
// Always outputs 1 item even when sheet is empty (0 input items)
const items = $input.all();
const existingUrls = items
  .map(i => (i.json.POSTEO || '').trim())
  .filter(Boolean)
  .join(',');
return [{ existingUrls }];
